        if (c == operators[i][0]) {
            return true;
        }
    }
    return false;
}

// Function to get the priority of the operator
int getPriority(char c) {
    for (int i = 0; i < 4; i++) {
        if (c == operators[i][0]) {
            return priority[i];
        }
    }
    return 0;
}

// Function to convert infix expression to postfix expression
string infixToPostfix(string infix) {
    string postfix;
    stack<char> opStack;
    for (char c : infix) {
        if (isdigit(c)) {
            postfix += c;
        } else if (c == '(') {
            opStack.push(c);
        } else if (c == ')') {
            while (!opStack.empty() && opStack.top() != '(') {
