                postfix += opStack.top();
                opStack.pop();
            }
            opStack.push(c);
        }
    }
    while (!opStack.empty()) {
        postfix += opStack.top();
        opStack.pop();
    }
    return postfix;
}

// Function to evaluate the postfix expression
double evaluatePostfix(string postfix) {
    stack<double> numStack;
    for (char c : postfix) {
        if (isdigit(c)) {
            numStack.push(c - '0');
